concept_explanation.auth_interceptor:
**Token authentication interceptor:**

```java
@GrpcGlobalServerInterceptor
public class AuthInterceptor implements ServerInterceptor {
    static final Metadata.Key<String> AUTH_KEY =
        Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);
    static final Context.Key<String> SERVICE_ID = Context.key("serviceId");

    @Override
    public <Req, Resp> ServerCall.Listener<Req> interceptCall(
            ServerCall<Req, Resp> call, Metadata headers,
            ServerCallHandler<Req, Resp> next) {

        String authHeader = headers.get(AUTH_KEY);
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            call.close(Status.UNAUTHENTICATED
                .withDescription("Bearer token required"), new Metadata());
            return new ServerCall.Listener<>() {}; // empty listener
        }

        String token = authHeader.substring("Bearer ".length());
        String serviceId = validateToken(token);
        if (serviceId == null) {
            call.close(Status.UNAUTHENTICATED
                .withDescription("Invalid or expired token"), new Metadata());
            return new ServerCall.Listener<>() {};
        }

        // Attach to context for downstream use:
        Context ctx = Context.current().withValue(SERVICE_ID, serviceId);
        return Contexts.interceptCall(ctx, call, headers, next);
    }

    private String validateToken(String token) {
        // In production: verify JWT signature, expiry, claims
        return tokenCache.getIfPresent(token); // returns serviceId or null
    }
}

// Service method can access serviceId:
public void detectFraud(FraudRequest req, StreamObserver<FraudResponse> obs) {
    String callerId = AuthInterceptor.SERVICE_ID.get();
    if (!allowedCallers.contains(callerId)) {
        obs.onError(Status.PERMISSION_DENIED
            .withDescription(callerId + " not authorized for fraud detection")
            .asRuntimeException());
        return;
    }
    // proceed...
}
```

